const tg = $input.first().json;
const msg = tg.message || tg.edited_message;
if (!msg) return [];
const text = (msg.text || msg.caption || '').trim();
if (!text || (msg.from && msg.from.is_bot)) return [];
const from = msg.from || {};
return [{ json: {
  tg_chat_id: String(msg.chat.id),
  message_text: text,
  name: [from.first_name, from.last_name].filter(Boolean).join(' ') || 'Гость',
  language: from.language_code || 'ru'
}}];

const ctx = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const extracted = $('📝 Извлечь').first().json;
const msg = extracted.message_text;

// Build client_memory block
const lines = [];
if (ctx.client_name) lines.push(`Имя: ${ctx.client_name}`);
if (ctx.client_stage && ctx.client_stage !== 'new') lines.push(`Стадия: ${ctx.client_stage}`);
if (ctx.client_country) lines.push(`Страна: ${ctx.client_country}`);
if (ctx.interests && ctx.interests.length) lines.push(`Интересы: ${ctx.interests.join(', ')}`);
if (ctx.budget_level && ctx.budget_level !== 'medium') lines.push(`Бюджет: ${ctx.budget_level}`);
if (ctx.travel_style) lines.push(`Стиль: ${ctx.travel_style}`);
if (ctx.last_tour_viewed) lines.push(`Последний тур: ${ctx.last_tour_viewed}`);
if (ctx.tours_viewed && ctx.tours_viewed.length) lines.push(`Смотрел туры: ${ctx.tours_viewed.join(', ')}`);
if (ctx.tours_booked && ctx.tours_booked.length) lines.push(`Забронировал: ${ctx.tours_booked.join(', ')}`);
const clientMemory = lines.length ? lines.join('\n') : 'Новый клиент, данных пока нет.';

// Build last_conversations block
let lastConvs = 'Первое обращение.';
try {
  const convs = typeof ctx.last_conversations === 'string'
    ? JSON.parse(ctx.last_conversations)
    : (ctx.last_conversations || []);
  if (convs && convs.length) {
    lastConvs = convs.slice(0, 5).reverse().map(c =>
      `Клиент: ${c.msg}\nКотЭ: ${c.res}`
    ).join('\n---\n');
  }
} catch(e) {}

return [{ json: {
  tg_chat_id: extracted.tg_chat_id,
  message_text: msg,
  client_id: ctx.client_id,
  client_name: ctx.client_name,
  client_stage: ctx.client_stage || 'new',
  is_new_client: ctx.is_new_client || false,
  client_memory: clientMemory,
  last_conversations: lastConvs
}}];

