const ai = $input.first().json;
const prev = $('✍️ Собрать промпт').first().json;
const reply = ai.candidates?.[0]?.content?.parts?.[0]?.text || 'Извините, не смог ответить. Попробуйте позже.';
return [{ json: { ...prev, ai_reply: reply } }];

const d = $input.first().json;
const text = (d.message_text || '').toLowerCase();

const interests = [];
if (/остров|море|пляж|пхи|симил|джеймс|снорклинг|яхт|морск/i.test(text)) interests.push('islands');
if (/актив|рафтинг|atv|квадро|мото|зиплайн|гиббон|слон|адренал/i.test(text)) interests.push('active');
if (/природ|джунгли|као.*сок|водопад|лес|нацпарк/i.test(text)) interests.push('nature');
if (/вечер|шоу|фаер|тиффани|муай|бокс|закат/i.test(text)) interests.push('evening');
if (/дети|ребенок|семья|детей|малыш|семейн/i.test(text)) interests.push('family');
if (/vip|яхта|премиум|luxury/i.test(text)) interests.push('vip');

let budget = null;
if (/дорого|бюджет|дешев|экономн/i.test(text)) budget = 'low';
if (/vip|не.*дорог|деньги.*не.*вопрос/i.test(text)) budget = 'vip';

let stage = null;
if (/забронир|оформ|хочу.*(тур|брон)|запис|оплат/i.test(text)) stage = 'booking';
else if (/потом|подумаю|позже|не.*сейчас|может/i.test(text)) stage = 'thinking';
else if (/не.*(нужно|надо|хочу|интересн)|нет.*спасибо/i.test(text)) stage = 'cold';
else if (interests.length || budget) stage = 'interest';

// last viewed tour
let lastTour = null;
const tourMap = [
  [/джеймс.*бонд|james/i, 'james'],
  [/пхи.пхи|phiphi/i, 'phiphi-bamboo'],
  [/симилан/i, 'similan'],
  [/мото.?тур|мотоцикл/i, 'moto'],
  [/рафтинг|slony|слон.*atv/i, 'raft'],
  [/гиббон|зиплайн/i, 'gibbon'],
  [/као.*сок/i, 'khaosok2'],
  [/яхт/i, 'yacht'],
  [/vip.*сопров/i, 'vip'],
  [/фаер.*шоу|fire/i, 'fire'],
  [/ко.*лан|kolan/i, 'kolan'],
  [/тиффани/i, 'tiffany']
];
for (const [re, slug] of tourMap) {
  if (re.test(text)) { lastTour = slug; break; }
}

return [{ json: {
  client_id: d.client_id,
  tg_chat_id: d.tg_chat_id,
  interests: interests.length ? interests : null,
  budget_level: budget,
  new_stage: stage,
  last_tour_viewed: lastTour,
  has_updates: !!(interests.length || budget || stage || lastTour)
}}];
